<?php
 namespace App\Models; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; class MemberFreezeLog extends Model { protected $fillable = [ 'member_id', 'freeze_fee', 'start_date', 'end_date', ]; protected $casts = [ 'start_date' => 'date', 'end_date' => 'date', 'freeze_fee' => 'decimal:2', ]; public function member(): BelongsTo { return $this->belongsTo(Member::class); } } 